+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import type {
+  NotificationLog,
+  NotificationLogQuery,
+  DeliveryStatus,
+} from '../models/notification-log.js';
+import type {
+  NotificationChannel,
+  NotificationType,
+  NotificationPayload,
+  NotificationResult,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+let nextLogId = 1;
+
+function generateLogId(): string {
+  return `log-${String(nextLogId++).padStart(4, '0')}`;
+}
+
+export function resetLogIdCounter(): void {
+  nextLogId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  recordDelivery(
+    payload: NotificationPayload,
+    result: NotificationResult,
+    userId?: string,
+  ): NotificationLog {
+    const status: DeliveryStatus = result.success ? 'sent' : 'failed';
+    const log: NotificationLog = {
+      id: generateLogId(),
+      notificationId: payload.id,
+      recipient: payload.recipient,
+      userId,
+      channel: payload.channel,
+      type: payload.type,
+      subject: payload.subject,
+      status,
+      error: result.error,
+      sentAt: result.deliveredAt,
+    };
+    this.logger.info(
+      `Recording ${status} notification ${payload.id} via ${payload.channel}`,
+    );
+    return this.repository.save(log);
+  }
+
+  recordSuppressed(
+    type: NotificationType,
+    channel: NotificationChannel,
+    recipient: string,
+    userId?: string,
+  ): NotificationLog {
+    const log: NotificationLog = {
+      id: generateLogId(),
+      notificationId: '',
+      recipient,
+      userId,
+      channel,
+      type,
+      subject: '',
+      status: 'suppressed',
+      sentAt: new Date(),
+    };
+    this.logger.info(
+      `Recording suppressed notification ${type} for ${recipient}`,
+    );
+    return this.repository.save(log);
+  }
+
+  getById(id: string): NotificationLog | undefined {
+    return this.repository.findById(id);
+  }
+
+  getByUserId(userId: string): NotificationLog[] {
+    return this.repository.findByUserId(userId);
+  }
+
+  getByType(type: NotificationType): NotificationLog[] {
+    return this.repository.findByType(type);
+  }
+
+  getByChannel(channel: NotificationChannel): NotificationLog[] {
+    return this.repository.findByChannel(channel);
+  }
+
+  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
+    return this.repository.findByDateRange(startDate, endDate);
+  }
+
+  query(filter: NotificationLogQuery): NotificationLog[] {
+    return this.repository.findAll((log) => {
+      if (filter.userId !== undefined && log.userId !== filter.userId) return false;
+      if (filter.channel !== undefined && log.channel !== filter.channel) return false;
+      if (filter.type !== undefined && log.type !== filter.type) return false;
+      if (filter.status !== undefined && log.status !== filter.status) return false;
+      if (filter.startDate !== undefined && log.sentAt < filter.startDate) return false;
+      if (filter.endDate !== undefined && log.sentAt > filter.endDate) return false;
+      return true;
+    });
+  }
+
+  getAll(): NotificationLog[] {
+    return this.repository.findAll();
+  }
+
+  count(): number {
+    return this.repository.count();
+  }
+}

