import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter, InMemoryTransport } from '../../src/adapters/email.adapter.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
import type { NotificationPayload, NotificationResult } from '../../src/models/notification.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('recordDelivery', () => {
    it('should record a successful delivery', () => {
      const payload: NotificationPayload = {
        id: 'notif-0001',
        type: 'order-confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        createdAt: new Date('2026-03-30T10:00:00Z'),
      };
      const result: NotificationResult = {
        success: true,
        notificationId: 'notif-0001',
        channel: 'email',
        deliveredAt: new Date('2026-03-30T10:00:01Z'),
      };

      const log = historyService.recordDelivery(payload, result, 'user-1');

      expect(log.id).toBe('log-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.userId).toBe('user-1');
      expect(log.channel).toBe('email');
      expect(log.type).toBe('order-confirmation');
      expect(log.subject).toBe('Order Confirmation');
      expect(log.status).toBe('sent');
      expect(log.error).toBeUndefined();
      expect(log.sentAt).toEqual(new Date('2026-03-30T10:00:01Z'));
    });

    it('should record a failed delivery', () => {
      const payload: NotificationPayload = {
        id: 'notif-0002',
        type: 'welcome',
        channel: 'email',
        recipient: 'bob@example.com',
        subject: 'Welcome',
        body: 'Welcome!',
        createdAt: new Date('2026-03-30T10:00:00Z'),
      };
      const result: NotificationResult = {
        success: false,
        notificationId: 'notif-0002',
        channel: 'email',
        error: 'SMTP connection refused',
        deliveredAt: new Date('2026-03-30T10:00:01Z'),
      };

      const log = historyService.recordDelivery(payload, result, 'user-2');

      expect(log.status).toBe('failed');
      expect(log.error).toBe('SMTP connection refused');
    });
  });

  describe('recordSuppressed', () => {
    it('should record a suppressed notification', () => {
      const log = historyService.recordSuppressed(
        'order-confirmation',
        'email',
        'alice@example.com',
        'user-1',
      );

      expect(log.id).toBe('log-0001');
      expect(log.status).toBe('suppressed');
      expect(log.type).toBe('order-confirmation');
      expect(log.channel).toBe('email');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.userId).toBe('user-1');
    });
  });

  describe('query methods', () => {
    beforeEach(() => {
      const payloads: NotificationPayload[] = [
        {
          id: 'n1', type: 'order-confirmation', channel: 'email',
          recipient: 'alice@example.com', subject: 'Order #1', body: '',
          createdAt: new Date('2026-03-28T10:00:00Z'),
        },
        {
          id: 'n2', type: 'order-status-update', channel: 'email',
          recipient: 'bob@example.com', subject: 'Order Update', body: '',
          createdAt: new Date('2026-03-29T10:00:00Z'),
        },
        {
          id: 'n3', type: 'welcome', channel: 'webhook',
          recipient: 'https://hooks.example.com', subject: 'Welcome', body: '',
          createdAt: new Date('2026-03-30T10:00:00Z'),
        },
      ];

      const results: NotificationResult[] = [
        { success: true, notificationId: 'n1', channel: 'email', deliveredAt: new Date('2026-03-28T10:00:01Z') },
        { success: false, notificationId: 'n2', channel: 'email', error: 'timeout', deliveredAt: new Date('2026-03-29T10:00:01Z') },
        { success: true, notificationId: 'n3', channel: 'webhook', deliveredAt: new Date('2026-03-30T10:00:01Z') },
      ];

      historyService.recordDelivery(payloads[0]!, results[0]!, 'user-1');
      historyService.recordDelivery(payloads[1]!, results[1]!, 'user-2');
      historyService.recordDelivery(payloads[2]!, results[2]!, 'user-3');
    });

    it('should get by user ID', () => {
      const logs = historyService.getByUserId('user-1');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.notificationId).toBe('n1');
    });

    it('should get by type', () => {
      const logs = historyService.getByType('welcome');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.channel).toBe('webhook');
    });

    it('should get by channel', () => {
      const logs = historyService.getByChannel('email');
      expect(logs).toHaveLength(2);
    });

    it('should get by date range', () => {
      const logs = historyService.getByDateRange(
        new Date('2026-03-29T00:00:00Z'),
        new Date('2026-03-30T23:59:59Z'),
      );
      expect(logs).toHaveLength(2);
    });

    it('should get by ID', () => {
      const log = historyService.getById('log-0001');
      expect(log).toBeDefined();
      expect(log!.notificationId).toBe('n1');
    });

    it('should count all logs', () => {
      expect(historyService.count()).toBe(3);
    });

    it('should get all logs', () => {
      expect(historyService.getAll()).toHaveLength(3);
    });
  });

  describe('query with combined filters', () => {
    beforeEach(() => {
      const payload: NotificationPayload = {
        id: 'n1', type: 'order-confirmation', channel: 'email',
        recipient: 'alice@example.com', subject: 'Order', body: '',
        createdAt: new Date('2026-03-28T10:00:00Z'),
      };
      const result: NotificationResult = {
        success: true, notificationId: 'n1', channel: 'email',
        deliveredAt: new Date('2026-03-28T10:00:01Z'),
      };
      historyService.recordDelivery(payload, result, 'user-1');

      const payload2: NotificationPayload = {
        id: 'n2', type: 'welcome', channel: 'email',
        recipient: 'alice@example.com', subject: 'Welcome', body: '',
        createdAt: new Date('2026-03-29T10:00:00Z'),
      };
      const result2: NotificationResult = {
        success: true, notificationId: 'n2', channel: 'email',
        deliveredAt: new Date('2026-03-29T10:00:01Z'),
      };
      historyService.recordDelivery(payload2, result2, 'user-1');

      historyService.recordSuppressed('order-status-update', 'email', 'alice@example.com', 'user-1');
    });

    it('should filter by userId and type', () => {
      const logs = historyService.query({ userId: 'user-1', type: 'welcome' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.type).toBe('welcome');
    });

    it('should filter by status', () => {
      const logs = historyService.query({ userId: 'user-1', status: 'suppressed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.type).toBe('order-status-update');
    });

    it('should filter by date range', () => {
      const logs = historyService.query({
        userId: 'user-1',
        startDate: new Date('2026-03-29T00:00:00Z'),
        endDate: new Date('2026-03-29T23:59:59Z'),
      });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.type).toBe('welcome');
    });

    it('should return empty when no matches', () => {
      const logs = historyService.query({ userId: 'no-such-user' });
      expect(logs).toHaveLength(0);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let transport: InMemoryTransport;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      transport = new InMemoryTransport();
      const emailAdapter = new EmailAdapter({
        transport,
        recipientResolver: async (recipient) => {
          if (recipient.includes('@')) return recipient;
          const emails: Record<string, string> = { 'user-1': 'alice@example.com' };
          return emails[recipient] ?? null;
        },
      });
      notificationService.registerAdapter(emailAdapter);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notification when sent via EventBus', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1', userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10, status: 'pending',
          createdAt: new Date(), updatedAt: new Date(),
        },
        user: {
          id: 'user-1', name: 'Alice', email: 'alice@example.com',
          role: 'member', createdAt: new Date(), updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('sent');
      expect(logs[0]!.type).toBe('order-confirmation');
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.userId).toBe('user-1');
    });

    it('should log suppressed notification when preferences block it', async () => {
      const prefsDb = new Database();
      const prefsRepo = new PreferencesRepository(prefsDb);
      const preferencesService = new PreferencesService(prefsRepo);
      notificationService.setPreferencesService(preferencesService);

      preferencesService.createPreferences({
        userId: 'user-1',
        email: { enabled: false },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1', userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10, status: 'pending',
          createdAt: new Date(), updatedAt: new Date(),
        },
        user: {
          id: 'user-1', name: 'Alice', email: 'alice@example.com',
          role: 'member', createdAt: new Date(), updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('suppressed');
      expect(logs[0]!.type).toBe('order-confirmation');
      expect(logs[0]!.userId).toBe('user-1');
    });

    it('should log multiple notifications from different events', async () => {
      const orderEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1', userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10, status: 'pending',
          createdAt: new Date(), updatedAt: new Date(),
        },
        user: {
          id: 'user-1', name: 'Alice', email: 'alice@example.com',
          role: 'member', createdAt: new Date(), updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const statusEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1', userId: 'user-1', items: [], total: 10,
          status: 'confirmed', createdAt: new Date(), updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(orderEvent);
      await eventBus.emit(statusEvent);

      expect(historyService.count()).toBe(2);
      const logs = historyService.getByUserId('user-1');
      expect(logs).toHaveLength(2);
      expect(logs.map((l) => l.type)).toContain('order-confirmation');
      expect(logs.map((l) => l.type)).toContain('order-status-update');
    });
  });
});
